SELECT COUNT(device_id) 
FROM devices 
WHERE device_group = 'Group B';

SELECT COUNT(device_id) 
FROM device_templates 
WHERE template_id = 1;

SELECT device_name 
FROM devices 
WHERE device_id NOT IN (
    SELECT device_id 
    FROM device_templates
);

SELECT COUNT(group_name) 
FROM device_groups 
WHERE group_status = 'active';

SELECT COUNT(*) 
FROM template_settings
WHERE template_id = 0;

SELECT device_id
FROM devices
WHERE device_id NOT IN (
  SELECT device_id 
  FROM device_templates
);
